import 'package:flutter_test/flutter_test.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/validators/recipe_validators.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/recipe.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/recipe_ingredient.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/instruction.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/ingredient.dart';\n\nvoid main() {\n  group('RecipeValidator Tests', () {\n    late Recipe validRecipe;\n    late List<RecipeIngredient> validIngredients;\n    late List<Instruction> validInstructions;\n\n    setUp(() {\n      validIngredients = [\n        const RecipeIngredient(\n          ingredientId: 'flour-001',\n          name: 'All-Purpose Flour',\n          quantity: 2.0,\n          unit: 'cups',\n        ),\n        const RecipeIngredient(\n          ingredientId: 'sugar-001',\n          name: 'Granulated Sugar',\n          quantity: 1.0,\n          unit: 'cup',\n        ),\n      ];\n\n      validInstructions = [\n        const Instruction(\n          id: 'inst-001',\n          stepNumber: 1,\n          description: 'Mix flour and sugar in a large bowl until well combined',\n        ),\n        const Instruction(\n          id: 'inst-002',\n          stepNumber: 2,\n          description: 'Add wet ingredients and mix until smooth batter forms',\n        ),\n      ];\n\n      validRecipe = Recipe(\n        id: 'recipe-001',\n        title: 'Simple Cake',\n        description: 'A delicious and easy cake recipe perfect for beginners',\n        authorId: 'user-001',\n        ingredients: validIngredients,\n        instructions: validInstructions,\n        servings: 8,\n        prepTime: const Duration(minutes: 15),\n        cookTime: const Duration(minutes: 30),\n        totalTime: const Duration(minutes: 45),\n      );\n    });\n\n    group('Valid Recipe Tests', () {\n      test('should validate a complete valid recipe', () {\n        final result = RecipeValidator.validateRecipe(validRecipe);\n\n        expect(result.isValid, true);\n        expect(result.errors, isEmpty);\n      });\n\n      test('should allow warnings for valid recipe', () {\n        final recipeWithWarnings = validRecipe.copyWith(\n          title: 'A' * 95, // Long title that triggers warning\n          description: 'Short desc', // Short description that triggers warning\n        );\n\n        final result = RecipeValidator.validateRecipe(recipeWithWarnings);\n\n        expect(result.isValid, true);\n        expect(result.errors, isEmpty);\n        expect(result.warnings.length, greaterThan(0));\n      });\n    });\n\n    group('Title Validation Tests', () {\n      test('should reject empty title', () {\n        final recipe = validRecipe.copyWith(title: '');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'title'), true);\n        expect(result.errors.any((e) => e.severity == ValidationSeverity.critical), true);\n      });\n\n      test('should reject title with only whitespace', () {\n        final recipe = validRecipe.copyWith(title: '   ');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'title'), true);\n      });\n\n      test('should reject title that is too short', () {\n        final recipe = validRecipe.copyWith(title: 'Hi');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'title'), true);\n      });\n\n      test('should warn about very long title', () {\n        final recipe = validRecipe.copyWith(title: 'A' * 150);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field == 'title'), true);\n      });\n    });\n\n    group('Description Validation Tests', () {\n      test('should reject empty description', () {\n        final recipe = validRecipe.copyWith(description: '');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'description'), true);\n      });\n\n      test('should warn about very short description', () {\n        final recipe = validRecipe.copyWith(description: 'Short');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field == 'description'), true);\n      });\n    });\n\n    group('Author Validation Tests', () {\n      test('should reject empty author ID', () {\n        final recipe = validRecipe.copyWith(authorId: '');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'authorId'), true);\n        expect(result.errors.any((e) => e.severity == ValidationSeverity.critical), true);\n      });\n\n      test('should reject whitespace-only author ID', () {\n        final recipe = validRecipe.copyWith(authorId: '   ');\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'authorId'), true);\n      });\n    });\n\n    group('Servings Validation Tests', () {\n      test('should reject zero servings', () {\n        final recipe = validRecipe.copyWith(servings: 0);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'servings'), true);\n      });\n\n      test('should reject negative servings', () {\n        final recipe = validRecipe.copyWith(servings: -1);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'servings'), true);\n      });\n\n      test('should warn about very large servings', () {\n        final recipe = validRecipe.copyWith(servings: 150);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field == 'servings'), true);\n      });\n    });\n\n    group('Ingredients Validation Tests', () {\n      test('should reject recipe with no ingredients', () {\n        final recipe = validRecipe.copyWith(ingredients: []);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'ingredients'), true);\n        expect(result.errors.any((e) => e.severity == ValidationSeverity.critical), true);\n      });\n\n      test('should validate individual ingredients', () {\n        final invalidIngredients = [\n          const RecipeIngredient(\n            ingredientId: 'flour-001',\n            name: '', // Invalid empty name\n            quantity: 2.0,\n            unit: 'cups',\n          ),\n          const RecipeIngredient(\n            ingredientId: 'sugar-001',\n            name: 'Sugar',\n            quantity: -1.0, // Invalid negative quantity\n            unit: 'cup',\n          ),\n        ];\n\n        final recipe = validRecipe.copyWith(ingredients: invalidIngredients);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field.contains('ingredients[0].name')), true);\n        expect(result.errors.any((e) => e.field.contains('ingredients[1].quantity')), true);\n      });\n\n      test('should warn about very large ingredient quantities', () {\n        final largeQuantityIngredients = [\n          const RecipeIngredient(\n            ingredientId: 'flour-001',\n            name: 'Flour',\n            quantity: 15000.0, // Very large quantity\n            unit: 'cups',\n          ),\n        ];\n\n        final recipe = validRecipe.copyWith(ingredients: largeQuantityIngredients);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field.contains('ingredients[0].quantity')), true);\n      });\n    });\n\n    group('Instructions Validation Tests', () {\n      test('should reject recipe with no instructions', () {\n        final recipe = validRecipe.copyWith(instructions: []);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'instructions'), true);\n        expect(result.errors.any((e) => e.severity == ValidationSeverity.critical), true);\n      });\n\n      test('should validate individual instructions', () {\n        final invalidInstructions = [\n          const Instruction(\n            id: 'inst-001',\n            stepNumber: 0, // Invalid step number\n            description: 'Mix ingredients',\n          ),\n          const Instruction(\n            id: 'inst-002',\n            stepNumber: 2,\n            description: '', // Invalid empty description\n          ),\n        ];\n\n        final recipe = validRecipe.copyWith(instructions: invalidInstructions);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field.contains('instructions[0].stepNumber')), true);\n        expect(result.errors.any((e) => e.field.contains('instructions[1].description')), true);\n      });\n\n      test('should warn about very short instruction descriptions', () {\n        final shortInstructions = [\n          const Instruction(\n            id: 'inst-001',\n            stepNumber: 1,\n            description: 'Mix', // Very short description\n          ),\n        ];\n\n        final recipe = validRecipe.copyWith(instructions: shortInstructions);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field.contains('instructions[0].description')), true);\n      });\n    });\n\n    group('Time Validation Tests', () {\n      test('should reject negative prep time', () {\n        final recipe = validRecipe.copyWith(prepTime: const Duration(minutes: -10));\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'prepTime'), true);\n      });\n\n      test('should reject negative cook time', () {\n        final recipe = validRecipe.copyWith(cookTime: const Duration(minutes: -5));\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'cookTime'), true);\n      });\n\n      test('should reject negative total time', () {\n        final recipe = validRecipe.copyWith(totalTime: const Duration(minutes: -15));\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'totalTime'), true);\n      });\n\n      test('should warn when total time is less than prep + cook time', () {\n        final recipe = validRecipe.copyWith(\n          prepTime: const Duration(minutes: 20),\n          cookTime: const Duration(minutes: 30),\n          totalTime: const Duration(minutes: 40), // Less than 50 minutes\n        );\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field == 'totalTime'), true);\n      });\n    });\n\n    group('Rating Validation Tests', () {\n      test('should reject negative rating', () {\n        final recipe = validRecipe.copyWith(rating: -1.0);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'rating'), true);\n      });\n\n      test('should reject rating above 5', () {\n        final recipe = validRecipe.copyWith(rating: 6.0);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'rating'), true);\n      });\n\n      test('should warn when rating exists but no reviews', () {\n        final recipe = validRecipe.copyWith(\n          rating: 4.5,\n          reviewCount: 0,\n        );\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field == 'reviewCount'), true);\n      });\n    });\n\n    group('Nutrition Validation Tests', () {\n      test('should validate nutrition summary', () {\n        const nutrition = NutritionSummary(\n          caloriesPerServing: -100.0, // Invalid negative calories\n          proteinPerServing: -5.0, // Invalid negative protein\n        );\n\n        final recipe = validRecipe.copyWith(nutrition: nutrition);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, false);\n        expect(result.errors.any((e) => e.field == 'nutrition.caloriesPerServing'), true);\n        expect(result.errors.any((e) => e.field == 'nutrition.proteinPerServing'), true);\n      });\n\n      test('should warn about very high calorie count', () {\n        const nutrition = NutritionSummary(\n          caloriesPerServing: 6000.0, // Very high calories\n        );\n\n        final recipe = validRecipe.copyWith(nutrition: nutrition);\n        final result = RecipeValidator.validateRecipe(recipe);\n\n        expect(result.isValid, true);\n        expect(result.warnings.any((w) => w.field == 'nutrition.caloriesPerServing'), true);\n      });\n    });\n  });\n\n  group('IngredientValidator Tests', () {\n    test('should validate a complete valid ingredient', () {\n      const ingredient = Ingredient(\n        id: 'flour-001',\n        name: 'All-Purpose Flour',\n        category: 'grains',\n        shelfLifeDays: 365,\n        averagePricePerUnit: 2.50,\n        densityGPerMl: 0.6,\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, true);\n      expect(result.errors, isEmpty);\n    });\n\n    test('should reject ingredient with empty name', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: '',\n        category: 'other',\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, false);\n      expect(result.errors.any((e) => e.field == 'name'), true);\n      expect(result.errors.any((e) => e.severity == ValidationSeverity.critical), true);\n    });\n\n    test('should reject ingredient with very short name', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: 'A',\n        category: 'other',\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, false);\n      expect(result.errors.any((e) => e.field == 'name'), true);\n    });\n\n    test('should reject ingredient with empty category', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: 'Test Ingredient',\n        category: '',\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, false);\n      expect(result.errors.any((e) => e.field == 'category'), true);\n    });\n\n    test('should reject negative shelf life', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: 'Test Ingredient',\n        category: 'other',\n        shelfLifeDays: -10,\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, false);\n      expect(result.errors.any((e) => e.field == 'shelfLifeDays'), true);\n    });\n\n    test('should warn about very long shelf life', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: 'Test Ingredient',\n        category: 'other',\n        shelfLifeDays: 5000, // More than 10 years\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, true);\n      expect(result.warnings.any((w) => w.field == 'shelfLifeDays'), true);\n    });\n\n    test('should reject negative price', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: 'Test Ingredient',\n        category: 'other',\n        averagePricePerUnit: -5.0,\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, false);\n      expect(result.errors.any((e) => e.field == 'averagePricePerUnit'), true);\n    });\n\n    test('should warn about zero density', () {\n      const ingredient = Ingredient(\n        id: 'ing-001',\n        name: 'Test Ingredient',\n        category: 'other',\n        densityGPerMl: 0.0,\n      );\n\n      final result = IngredientValidator.validateIngredient(ingredient);\n\n      expect(result.isValid, true);\n      expect(result.warnings.any((w) => w.field == 'densityGPerMl'), true);\n    });\n  });\n\n  group('RecipeDifficultyCalculator Tests', () {\n    test('should calculate beginner difficulty for simple recipe', () {\n      final simpleRecipe = Recipe(\n        id: 'simple-001',\n        title: 'Toast',\n        description: 'Simple toast',\n        authorId: 'user-001',\n        ingredients: [\n          const RecipeIngredient(\n            ingredientId: 'bread-001',\n            name: 'Bread',\n            quantity: 2.0,\n            unit: 'slices',\n          ),\n        ],\n        instructions: [\n          const Instruction(\n            id: 'inst-001',\n            stepNumber: 1,\n            description: 'Toast bread until golden',\n          ),\n        ],\n        servings: 1,\n        totalTime: const Duration(minutes: 5),\n      );\n\n      final difficulty = RecipeDifficultyCalculator.calculateDifficulty(simpleRecipe);\n      expect(difficulty, RecipeDifficulty.beginner);\n    });\n\n    test('should calculate expert difficulty for complex recipe', () {\n      final complexRecipe = Recipe(\n        id: 'complex-001',\n        title: 'Beef Wellington',\n        description: 'Complex pastry dish',\n        authorId: 'user-001',\n        ingredients: List.generate(20, (i) => RecipeIngredient(\n          ingredientId: 'ing-$i',\n          name: 'Ingredient $i',\n          quantity: 1.0,\n          unit: 'piece',\n        )),\n        instructions: List.generate(25, (i) => Instruction(\n          id: 'inst-$i',\n          stepNumber: i + 1,\n          description: 'Complex step $i',\n          techniques: ['sous_vide', 'tempering'],\n        )),\n        servings: 8,\n        totalTime: const Duration(hours: 6),\n        equipment: ['sous_vide_machine', 'stand_mixer'],\n      );\n\n      final difficulty = RecipeDifficultyCalculator.calculateDifficulty(complexRecipe);\n      expect(difficulty, RecipeDifficulty.expert);\n    });\n\n    test('should provide difficulty descriptions', () {\n      expect(RecipeDifficultyCalculator.getDifficultyDescription(RecipeDifficulty.beginner),\n          contains('first-time cooks'));\n      expect(RecipeDifficultyCalculator.getDifficultyDescription(RecipeDifficulty.expert),\n          contains('professional-level'));\n    });\n  });\n\n  group('NutritionEstimator Tests', () {\n    test('should estimate nutrition from ingredients', () {\n      final nutritionInfo = NutritionInfo(\n        calories: 364.0,\n        protein: 10.3,\n        carbohydrates: 76.3,\n        fat: 1.9,\n      );\n\n      final recipe = Recipe(\n        id: 'recipe-001',\n        title: 'Test Recipe',\n        description: 'Test',\n        authorId: 'user-001',\n        ingredients: [\n          RecipeIngredient(\n            ingredientId: 'flour-001',\n            name: 'Flour',\n            quantity: 100.0, // 100g\n            unit: 'g',\n            nutritionInfo: nutritionInfo,\n          ),\n        ],\n        instructions: [\n          const Instruction(\n            id: 'inst-001',\n            stepNumber: 1,\n            description: 'Mix',\n          ),\n        ],\n        servings: 2,\n      );\n\n      final nutrition = NutritionEstimator.estimateNutrition(recipe);\n\n      expect(nutrition.caloriesPerServing, 182.0); // 364 / 2 servings\n      expect(nutrition.proteinPerServing, 5.15); // 10.3 / 2 servings\n      expect(nutrition.carbsPerServing, 38.15); // 76.3 / 2 servings\n      expect(nutrition.fatPerServing, 0.95); // 1.9 / 2 servings\n    });\n\n    test('should calculate health score', () {\n      final recipe = Recipe(\n        id: 'recipe-001',\n        title: 'Healthy Recipe',\n        description: 'Test',\n        authorId: 'user-001',\n        ingredients: [\n          const RecipeIngredient(\n            ingredientId: 'chicken-001',\n            name: 'Chicken Breast',\n            quantity: 200.0,\n            unit: 'g',\n            nutritionInfo: NutritionInfo(\n              calories: 165.0,\n              protein: 31.0,\n              carbohydrates: 0.0,\n              fat: 3.6,\n              fiber: 0.0,\n              sodium: 74.0,\n            ),\n          ),\n        ],\n        instructions: [\n          const Instruction(\n            id: 'inst-001',\n            stepNumber: 1,\n            description: 'Cook chicken',\n          ),\n        ],\n        servings: 1,\n      );\n\n      final nutrition = NutritionEstimator.estimateNutrition(recipe);\n\n      expect(nutrition.healthScore, isNot(NutritionScore.unknown));\n      expect(nutrition.isHighProtein, true);\n      expect(nutrition.isLowCarb, true);\n    });\n  });\n\n  group('RecipeBusinessRules Tests', () {\n    test('should allow publishing valid recipe with image', () {\n      final recipe = validRecipe.copyWith(\n        imageUrls: ['https://example.com/recipe.jpg'],\n        tags: ['cake', 'dessert'],\n        cuisineTypes: ['american'],\n        mealTypes: ['dessert'],\n      );\n\n      final result = RecipeBusinessRules.canPublish(recipe);\n\n      expect(result.isValid, true);\n      expect(result.errors, isEmpty);\n    });\n\n    test('should reject publishing recipe without image', () {\n      final recipe = validRecipe.copyWith(imageUrls: []);\n      final result = RecipeBusinessRules.canPublish(recipe);\n\n      expect(result.isValid, false);\n      expect(result.errors.any((e) => e.field == 'imageUrls'), true);\n    });\n\n    test('should warn about missing metadata for publishing', () {\n      final recipe = validRecipe.copyWith(\n        imageUrls: ['https://example.com/recipe.jpg'],\n        tags: [], // Missing tags\n        cuisineTypes: [], // Missing cuisine types\n        mealTypes: [], // Missing meal types\n      );\n\n      final result = RecipeBusinessRules.canPublish(recipe);\n\n      expect(result.isValid, true);\n      expect(result.warnings.length, greaterThan(0));\n      expect(result.warnings.any((w) => w.field == 'tags'), true);\n      expect(result.warnings.any((w) => w.field == 'cuisineTypes'), true);\n      expect(result.warnings.any((w) => w.field == 'mealTypes'), true);\n    });\n\n    test('should check edit permissions correctly', () {\n      const recipe = Recipe(\n        id: 'recipe-001',\n        title: 'Test Recipe',\n        description: 'Test',\n        authorId: 'user-001',\n        servings: 1,\n        status: RecipeStatus.published,\n      );\n\n      expect(RecipeBusinessRules.canEdit(recipe, 'user-001'), true); // Author can edit\n      expect(RecipeBusinessRules.canEdit(recipe, 'user-002'), false); // Non-author cannot edit published\n\n      const draftRecipe = recipe.copyWith(status: RecipeStatus.draft);\n      expect(RecipeBusinessRules.canEdit(draftRecipe, 'user-002'), true); // Anyone can edit draft\n    });\n\n    test('should check delete permissions correctly', () {\n      const recipe = Recipe(\n        id: 'recipe-001',\n        title: 'Test Recipe',\n        description: 'Test',\n        authorId: 'user-001',\n        servings: 1,\n      );\n\n      expect(RecipeBusinessRules.canDelete(recipe, 'user-001'), true); // Author can delete\n      expect(RecipeBusinessRules.canDelete(recipe, 'user-002'), false); // Non-author cannot delete\n    });\n\n    test('should provide business rule constants', () {\n      expect(RecipeBusinessRules.getMaxIngredients(), 50);\n      expect(RecipeBusinessRules.getMaxInstructions(), 100);\n      expect(RecipeBusinessRules.getMaxTitleLength(), 100);\n      expect(RecipeBusinessRules.getMaxDescriptionLength(), 2000);\n    });\n  });\n}\n